func solve(nums []int64) int64 {
	// The problem asks for the maximum number of fixed points we can achieve in the resulting subsequence.
	// If we keep a subsequence of original indices i_0, i_1, ..., i_{k-1} (where i_0 < i_1 < ... < i_{k-1}),
	// the element nums[i_j] ends up at new index j.
	// We want to maximize the count of j such that nums[i_j] = j.

	// This is equivalent to finding the longest subsequence such that the j-th element of the subsequence
	// has the value j.

	// We can use a greedy approach. We iterate through the original array `nums` and try to match
	// nums[i] to the next required index 'j' we are looking for.

	// 'targetIndex' tracks the index 'j' of the next fixed point we are trying to achieve.
	// We start by looking for a fixed point at index j=0.
	targetIndex := int64(0)

	for _, val := range nums {
		// If the current value `val` matches the required index `targetIndex`,
		// we choose to keep this element in our subsequence, as it contributes to a fixed point.
		if val == targetIndex {
			// We successfully found a fixed point at index 'targetIndex'.
			// We increment 'targetIndex' to start looking for the next fixed point (at index targetIndex + 1).
			targetIndex++
		}
		// If val != targetIndex, we skip this element (effectively deleting it), hoping a later element
		// matches 'targetIndex'.
	}

	// targetIndex now holds (maximum number of fixed points found) + 1.
	// Thus, the maximum number of fixed points is targetIndex - 1.
	return targetIndex - 1
}
